static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard3dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    // Input x: [N, C, D, H, W]
    const gert::Shape *x_shape = context->GetInputShape(0);
    // Weight: [O, C, KD, KH, KW]
    const gert::Shape *w_shape = context->GetInputShape(1);

    if (x_shape->IsUnknownShape() || w_shape->IsUnknownShape()) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N  = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t C  = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t Di = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t Hi = static_cast<uint32_t>(x_shape->GetDim(3));
    const uint32_t Wi = static_cast<uint32_t>(x_shape->GetDim(4));

    const uint32_t O  = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t Cw = static_cast<uint32_t>(w_shape->GetDim(1));
    const uint32_t Kd = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t Kh = static_cast<uint32_t>(w_shape->GetDim(3));
    const uint32_t Kw = static_cast<uint32_t>(w_shape->GetDim(4));

    if (C != Cw) {
        return ge::GRAPH_FAILED;
    }

    // stride=(1,1,1), dilation=(1,1,1), padding=(0,0,0)
    const uint32_t Do = (Di >= Kd) ? (Di - Kd + 1) : 0;
    const uint32_t Ho = (Hi >= Kh) ? (Hi - Kh + 1) : 0;
    const uint32_t Wo = (Wi >= Kw) ? (Wi - Kw + 1) : 0;

    // Select a reasonable blockDim based on total output positions (excluding O).
    uint64_t total_pos = static_cast<uint64_t>(N) * Do * Ho * Wo;
    uint32_t blockDim = static_cast<uint32_t>(total_pos);
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_c(C);
    tiling.set_d(Di);
    tiling.set_h(Hi);
    tiling.set_w(Wi);
    tiling.set_o(O);
    tiling.set_kd(Kd);
    tiling.set_kh(Kh);
    tiling.set_kw(Kw);
    tiling.set_od(Do);
    tiling.set_oh(Ho);
    tiling.set_ow(Wo);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace_sizes = context->GetWorkspaceSizes(1);
    workspace_sizes[0] = 0;

    return ge::GRAPH_SUCCESS;
}

