static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0); // [N,C,D,H,W]
    const gert::Shape *w_shape = context->GetInputShape(1); // [O,C,KD,KH,KW]
    if (x_shape == nullptr || w_shape == nullptr) {
        return GRAPH_FAILED;
    }
    const int64_t N  = x_shape->GetDim(0);
    const int64_t C  = x_shape->GetDim(1);
    const int64_t Di = x_shape->GetDim(2);
    const int64_t Hi = x_shape->GetDim(3);
    const int64_t Wi = x_shape->GetDim(4);

    const int64_t O  = w_shape->GetDim(0);
    const int64_t Cw = w_shape->GetDim(1);
    const int64_t Kd = w_shape->GetDim(2);
    const int64_t Kh = w_shape->GetDim(3);
    const int64_t Kw = w_shape->GetDim(4);

    if (C != Cw) {
        return GRAPH_FAILED;
    }

    // stride=(1,1,1), dilation=(1,1,1), padding=(0,0,0)
    const int64_t Do = (Di >= Kd) ? (Di - Kd + 1) : 0;
    const int64_t Ho = (Hi >= Kh) ? (Hi - Kh + 1) : 0;
    const int64_t Wo = (Wi >= Kw) ? (Wi - Kw + 1) : 0;

    gert::Shape *y_shape = context->GetOutputShape(0);
    std::vector<int64_t> out_dims = {N, O, Do, Ho, Wo};
    y_shape->SetDimNum(out_dims.size());
    for (size_t i = 0; i < out_dims.size(); ++i) {
        y_shape->SetDim(i, out_dims[i]);
    }
    return GRAPH_SUCCESS;
}

